/// Parameters that are required to generate or verify dCVC (Dynamic Card
/// Verification Code).
pub const DiscoverDynamicCardVerificationCode = struct {
    /// The transaction counter value that comes from the terminal.
    application_transaction_counter: []const u8,

    /// The expiry date of a payment card.
    card_expiry_date: []const u8,

    /// A random number that is generated by the issuer.
    unpredictable_number: []const u8,

    pub const json_field_names = .{
        .application_transaction_counter = "ApplicationTransactionCounter",
        .card_expiry_date = "CardExpiryDate",
        .unpredictable_number = "UnpredictableNumber",
    };
};
